    public Object parseFixedFloatValue(Object input)
    {
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(input, null))) || Helpers.isTrue((Helpers.isEqual(input, "-")))))
        {
            return null;
        }
        if (Helpers.isTrue(Helpers.isEqual(input, "")))
        {
            return 0;
        }
        Object isPercentage = (Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(input, "%"), 0));
        Object parts = Helpers.split(input, " ");
        Object value = Helpers.replace((String)Helpers.GetValue(parts, 0), (String)"%", (String)"");
        Object result = Helpers.parseFloat(value);
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isGreaterThan(result, 0))) && Helpers.isTrue(isPercentage)))
        {
            throw new ExchangeError((String)Helpers.add(Helpers.add(this.id, " parseFixedFloatValue() detected an unsupported non-zero percentage-based fee "), input)) ;
        }
        return result;
    }

