            put( "bid", ExmoCore.this.safeString(ticker, "buy_price") );
            put( "bidVolume", null );
            put( "ask", ExmoCore.this.safeString(ticker, "sell_price") );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", null );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
