    public Object sign(Object path, Object... optionalArgs)
    {
        Object api = Helpers.getArg(optionalArgs, 0, "public");
        Object method = Helpers.getArg(optionalArgs, 1, "GET");
        Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
        Object headers = Helpers.getArg(optionalArgs, 3, null);
        Object body = Helpers.getArg(optionalArgs, 4, null);
        Object url = Helpers.add(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), api), "/");
        if (Helpers.isTrue(!Helpers.isEqual(api, "web")))
        {
            url = Helpers.add(url, Helpers.add(this.version, "/"));
        }
        url = Helpers.add(url, path);
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(api, "public"))) || Helpers.isTrue((Helpers.isEqual(api, "web")))))
        {
            if (Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(parameters))))
            {
                url = Helpers.add(url, Helpers.add("?", this.urlencode(parameters)));
            }
        } else if (Helpers.isTrue(Helpers.isEqual(api, "private")))
        {
            this.checkRequiredCredentials();
            Object nonce = this.nonce();
            body = this.urlencode(this.extend(new java.util.HashMap<String, Object>() {{
                put( "nonce", nonce );
            }}, parameters));
            final Object finalBody = body;
            headers = new java.util.HashMap<String, Object>() {{
                put( "Content-Type", "application/x-www-form-urlencoded" );
                put( "Key", ExmoCore.this.apiKey );
                put( "Sign", ExmoCore.this.hmac(ExmoCore.this.encode(finalBody), ExmoCore.this.encode(ExmoCore.this.secret), sha512()) );
            }};
        }
        final Object finalUrl = url;
        final Object finalBody_2 = body;
        final Object finalHeaders = headers;
        return new java.util.HashMap<String, Object>() {{
            put( "url", finalUrl );
            put( "method", method );
            put( "body", finalBody_2 );
            put( "headers", finalHeaders );
        }};
    }

    public Object nonce()
    {
        return this.milliseconds();
    }

    public Object handleErrors(Object httpCode, Object reason, Object url, Object method, Object headers, Object body, Object response, Object requestHeaders, Object requestBody)
    {
        if (Helpers.isTrue(Helpers.isEqual(response, null)))
        {
            return null;  // fallback to default error handler
        }
        if (Helpers.isTrue(Helpers.isTrue((Helpers.inOp(response, "error"))) && !Helpers.isTrue((Helpers.inOp(response, "result")))))
        {
            // error: {
            //     "code": "140434",
            //     "msg": "Your margin balance is not sufficient to place the order for '5 TON'. Please top up your margin wallet by "2.5 USDT"."
            // }
            //
            Object errorCode = this.safeValue(response, "error", new java.util.HashMap<String, Object>() {{}});
            Object messageError = this.safeString(errorCode, "msg");
            Object code = this.safeString(errorCode, "code");
            Object feedback = Helpers.add(Helpers.add(this.id, " "), body);
            this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), code, feedback);
            this.throwBroadlyMatchedException(Helpers.GetValue(this.exceptions, "broad"), messageError, feedback);
            throw new ExchangeError((String)feedback) ;
        }
        if (Helpers.isTrue(Helpers.isTrue((Helpers.inOp(response, "result"))) || Helpers.isTrue((Helpers.inOp(response, "errmsg")))))
        {
            //
            //     {"result":false,"error":"Error 50052: Insufficient funds"}
            //     {"s":"error","errmsg":"strconv.ParseInt: parsing \"\": invalid syntax"}
            //
            Object success = this.safeBool(response, "result", false);
            if (Helpers.isTrue((success instanceof String)))
            {
                if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(success, "true"))) || Helpers.isTrue((Helpers.isEqual(success, "1")))))
                {
                    success = true;
                } else
                {
                    success = false;
                }
            }
            if (!Helpers.isTrue(success))
            {
                Object code = null;
                Object message = this.safeString2(response, "error", "errmsg");
                Object errorParts = Helpers.split(message, ":");
                Object numParts = Helpers.getArrayLength(errorParts);
                if (Helpers.isTrue(Helpers.isGreaterThan(numParts, 1)))
                {
                    Object errorSubParts = Helpers.split(Helpers.GetValue(errorParts, 0), " ");
                    Object numSubParts = Helpers.getArrayLength(errorSubParts);
                    code = ((Helpers.isTrue((Helpers.isGreaterThan(numSubParts, 1))))) ? Helpers.GetValue(errorSubParts, 1) : Helpers.GetValue(errorSubParts, 0);
                }
                Object feedback = Helpers.add(Helpers.add(this.id, " "), body);
                this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), code, feedback);
                this.throwBroadlyMatchedException(Helpers.GetValue(this.exceptions, "broad"), message, feedback);
                throw new ExchangeError((String)feedback) ;
            }
        }
        return null;
    }
